Ambapo SOAPLoggingHandler ni (iliyotolewa kutoka mifano iliyounganishwa):

```java
package com.myfirm.util.logging.ws;
import java.io.PrintStream;
import java.util.Map;
import java.util.Set;
import javax.xml.namespace.QName;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
/*
 * Hii SOAPHandler rahisi itatoa yaliyomo ya ujumbe unaoingia
 * na unaotoka.
 */
public class SOAPLoggingHandler implements SOAPHandler {
    // badilisha hii ili kuelekeza pato ikiwa inahitajika
    private static PrintStream out = System.out;
    public Set getHeaders() {
        return null;
    }
    public boolean handleMessage(SOAPMessageContext smc) {
        logToSystemOut(smc);
        return true;
    }
    public boolean handleFault(SOAPMessageContext smc) {
        logToSystemOut(smc);
        return true;
    }
    // hakuna cha kusafisha
    public void close(MessageContext messageContext) {
    }
    /*
     * Angalia MESSAGE_OUTBOUND_PROPERTY katika muktadha
     * kuona ikiwa huu ni ujumbe unaotoka au unaoingia.
     * Andika ujumbe mfupi kwa mkondo wa kuchapisha na
     * toa ujumbe. Njia ya writeTo() inaweza kutoa
     * SOAPException au IOException
     */
    private void logToSystemOut(SOAPMessageContext smc) {
        Boolean outboundProperty = (Boolean)
            smc.get (MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (outboundProperty.booleanValue()) {
            out.println("\nUjumbe unaotoka:");
        } else {
            out.println("\nUjumbe unaoingia:");
        }
        SOAPMessage message = smc.getMessage();
        try {
            message.writeTo(out);
            out.println("");   // kuongeza tu mstari mpya
        } catch (Exception e) {
            out.println("Exception in handler: " + e);
        }
    }
}
```

