```csharp
using System;
using System.Collections.Generic;

public class NQueens
{
    private int n;
    private int[] queens; // queens[i] = column where queen in row i is placed
    private List<int[]> solutions = new List<int[]>();

    public NQueens(int n)
    {
        this.n = n;
        this.queens = new int[n];
    }

    public List<int[]> SolveNQueens()
    {
        SolveNQueensUtil(0);
        return solutions;
    }

    private void SolveNQueensUtil(int row)
    {
        if (row == n)
        {
            // Found a solution, add it to the list
            solutions.Add((int[])queens.Clone()); //Important: Clone to avoid modification
            return;
        }

        for (int col = 0; col < n; col++)
        {
            queens[row] = col;
            if (IsSafe(row))
            {
                SolveNQueensUtil(row + 1);
            }
        }
    }

    private bool IsSafe(int row)
    {
        for (int i = 0; i < row; i++)
        {
            // Check same column
            if (queens[i] == queens[row])
            {
                return false;
            }

            // Check diagonals
            if (Math.Abs(queens[i] - queens[row]) == row - i)
            {
                return false;
            }
        }
        return true;
    }

    public static void PrintSolution(int[] solution)
    {
        int n = solution.Length;
        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (solution[i] == j)
                {
                    Console.Write("Q ");
                }
                else
                {
                    Console.Write(". ");
                }
            }
            Console.WriteLine();
        }
        Console.WriteLine();
    }

    public static void Main(string[] args)
    {
        int n = 4; // Change this to the desired board size
        NQueens nQueens = new NQueens(n);
        List<int[]> solutions = nQueens.SolveNQueens();

        Console.WriteLine($"Found {solutions.Count} solutions for N = {n}");
        foreach (int[] solution in solutions)
        {
            PrintSolution(solution);
        }
    }
}
