```csharp
// Msimbo wa C# wa uwekaji wa Malkia n
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // ukubwa wa juu wa ubao wa chess
    static int MAX = 10;

    // safu ya kuhifadhi uwekaji wa malkia
    static int[] arr = new int[MAX];

    // kigezo cha kuhesabu idadi ya suluhisho zilizopatikana
    static int no;

    // kitendakazi cha kujirudia kupata suluhisho
    static void nQueens(int k, int n)
    {
        // jaribu nafasi zote zinazowezekana kwa malkia katika safu ya sasa
        for (int i = 1; i <= n; i++)
        {
            // angalia ikiwa malkia anaweza kuwekwa katika nafasi ya sasa
            if (canPlace(k, i))
            {
                // weka malkia katika nafasi ya sasa
                arr[k] = i;

                // ikiwa malkia wote wamewekwa, onyesha suluhisho
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // jaribu kujirudia kuweka malkia waliobaki
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // kitendakazi saidizi cha kuangalia ikiwa malkia anaweza kuwekwa katika nafasi ya sasa
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // angalia ikiwa malkia tayari amewekwa kwenye nguzo au ulalo sawa
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // kitendakazi cha kuonyesha suluhisho
    static void display(int n)
    {
        breakLine();
        Console.Write("Mpangilio No. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // chapa '_' kwa seli tupu na 'Q' kwa seli iliyo na malkia
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // Msimbo Endeshaji wa kuanzisha tatizo na kuita kitendakazi tendaji
    public static void Main(String[] args)
    {
        int n = 4; // ukubwa wa ubao wa chess
        nQueens(1, n);
    }
}
