```python
# Programu ya Python ya kuchapisha nambari kuu za ziada (super primes) ambazo ni ndogo au sawa na n.

# Tengeneza nambari zote tasa ambazo ni ndogo kuliko n ukitumia Sieve ya Eratosthenes.
def sieve(n):
    is_prime = [True for i in range(n+1)]
    is_prime[0] = False
    is_prime[1] = False

    for p in range(2,n+1):
        if is_prime[p]:
            for i in range(2*p, n+1, p):
                is_prime[i] = False

    return is_prime

def super_primes(n):
    # Tengeneza nambari zote tasa
    is_prime = sieve(n)

    # Hifadhi nambari zote tasa kwenye safu
    primes = [i for i, prime in enumerate(is_prime) if prime]
    primes = [0] + primes
    for i, p in enumerate(primes):
        if is_prime[i]:
            yield p
```

Algorithm ya Dijkstra inafanana sana na algorithm ya Prim ya mti mdogo unaoenea. Kama vile MST ya Prim, tengeneza SPT (mti mfupi wa njia) na chanzo fulani kama mzizi. Dumisha seti mbili, seti moja ina vipeo vilivyojumuishwa kwenye mti mfupi wa njia, seti nyingine inajumuisha vipeo ambavyo bado havijajumuishwa kwenye mti mfupi wa njia. Katika kila hatua ya algorithm, tafuta kipeo ambacho kiko kwenye seti nyingine (seti ambayo bado haijajumuishwa) na ina umbali mdogo kutoka kwa chanzo.

```c
// Programu inalenga kutekeleza algorithm ya Dijkstra ya njia fupi zaidi ya chanzo kimoja katika lugha ya C.
// Programu hutumia tumbo la ukaribu kama uwakilishi wa grafu.

#include <limits.h>
#include <stdbool.h>
#include <stdio.h>

// Nambari ya vipeo vilivyopo kwenye grafu.
#define V 9

// Kitendakazi kinachotumika kutambua kipeo chenye thamani ndogo zaidi ya umbali
// miongoni mwa seti ya vipeo ambavyo bado havijajumuishwa kwenye mti mfupi zaidi wa njia.
int findMinDistance(int dist[], bool sptSet[])
{
    // Anzisha thamani ndogo
    int min = INT_MAX, min_index;

    for (int v = 0; v < V; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;
    return min_index;
}

// Kitendakazi cha matumizi cha kuchapisha umbali ulioundwa
// safu
void printSolution(int dist[])
{
    printf("Kipeo \t\t Umbali kutoka Chanzo\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t\t\t %d\n", i, dist[i]);
}

// kitendakazi kinachotumia algorithm ya Dijkstra kupata njia fupi kati ya
// nodi moja ya chanzo na nodi zingine zote kwenye grafu. Grafu inawakilishwa kwa kutumia
// tumbo la ukaribu.
void dijkstra(int graph[V][V], int src)
{
    int dist[V];
    bool processed[V];
    int i, u, v;

    // Anzisha umbali zote kama usio na kikomo na zilizochakatwa kama za uongo
    for (i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        processed[i] = false;
    }

    // Umbali wa kipeo cha chanzo kutoka kwake daima ni 0
    dist[src] = 0;

    // Tafuta njia fupi zaidi kwa vipeo vyote
    for (i = 0; i < V - 1; i++) {
        // Chagua kipeo cha umbali wa chini kabisa kutoka kwa seti ya vipeo ambavyo bado havijachakatwa
        u = -1;
        for (i = 0; i < V; i++) {
            if (!processed[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }

        // Weka alama kwenye kipeo kilichochaguliwa kama kilichochakatwa
        processed[u] = true;

        // Sasisha thamani ya umbali wa vipeo vilivyo karibu na kipeo kilichochaguliwa
        for (v = 0; v < V; v++) {
            if (graph[u][v] != 0 && !processed[v]) {
                int new_dist = dist[u] + graph[u][v];
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                }
            }
        }
    }

    // Chapisha safu ya umbali iliyoundwa
    printSolution(dist);
}


int main()
{
    /*  Unda grafu mfano */
    int graph[V][V] = { { 0, 4, 0, 0, 0, 0, 0, 8, 0 },
                        { 4, 0, 8, 0, 0, 0, 0, 11, 0 },
                        { 0, 8, 0, 7, 0, 4, 0, 0, 2 },
                        { 0, 0, 7, 0, 9, 14, 0, 0, 0 },
                        { 0, 0, 0, 9, 0, 10, 0, 0, 0 },
                        { 0, 0, 4, 14, 10, 0, 2, 0, 0 },
                        { 0, 0, 0, 0, 0, 2, 0, 1, 6 },
                        { 8, 11, 0, 0, 0, 0, 1, 0, 7 },
                        { 0, 0, 2, 0, 0, 0, 6, 7, 0 } };

        // Simu ya kitendakazi
        dijkstra(graph, 0);

        return 0;
}
```

