import java.util.*;

class Edge implements Comparable<Edge> {
    int src, dest, weight;

    public Edge(int src, int dest, int weight) {
        this.src = src;
        this.dest = dest;
        this.weight = weight;
    }

    @Override
    public int compareTo(Edge other) {
        return this.weight - other.weight;
    }
}

public class MinCostConnectCities {

    public static int minCostConnectCities(int n, int[][] points) {
        List<Edge> edges = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int weight = Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
                edges.add(new Edge(i, j, weight));
            }
        }

        Collections.sort(edges);

        int minCost = 0;
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }

        int edgeCount = 0;
        for (Edge edge : edges) {
            int srcParent = find(parent, edge.src);
            int destParent = find(parent, edge.dest);

            if (srcParent != destParent) {
                union(parent, srcParent, destParent);
                minCost += edge.weight;
                edgeCount++;
            }
            if(edgeCount == n -1) break; //optimization: stop when all nodes are connected
        }

        return minCost;
    }

    private static int find(int[] parent, int i) {
        if (parent[i] == i) {
            return i;
        }
        return parent[i] = find(parent, parent[i]); // Path compression
    }

    private static void union(int[] parent, int x, int y) {
        int xRoot = find(parent, x);
        int yRoot = find(parent, y);
        parent[xRoot] = yRoot;
    }

    public static void main(String[] args) {
        int n = 3;
        int[][] points = {{0,0},{2,2},{3,10}};
        int minCost = minCostConnectCities(n, points);
        System.out.println("Minimum cost to connect all cities: " + minCost); // Output: 17

        n = 5;
        points = new int[][]{{0,0},{2,2},{3,10},{5,2},{7,0}};
        minCost = minCostConnectCities(n, points);
        System.out.println("Minimum cost to connect all cities: " + minCost); // Output: 20
    }
}
