import java.util.*;

class Edge implements Comparable<Edge> {
    int chanzo, lengo, uzito;

    public Edge(int chanzo, int lengo, int uzito) {
        this.chanzo = chanzo;
        this.lengo = lengo;
        this.uzito = uzito;
    }

    @Override
    public int compareTo(Edge nyingine) {
        return this.uzito - nyingine.uzito;
    }
}

public class GharamaNdogoUnganishaMiji {

    public static int gharamaNdogoUnganishaMiji(int n, int[][] pointi) {
        List<Edge> kingo = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int uzito = Math.abs(pointi[i][0] - pointi[j][0]) + Math.abs(pointi[i][1] - pointi[j][1]);
                kingo.add(new Edge(i, j, uzito));
            }
        }

        Collections.sort(kingo);

        int gharamaNdogo = 0;
        int[] mzazi = new int[n];
        for (int i = 0; i < n; i++) {
            mzazi[i] = i;
        }

        int idadiKingo = 0;
        for (Edge kingo : kingo) {
            int mzaziChanzo = find(mzazi, kingo.chanzo);
            int mzaziLengo = find(mzazi, kingo.lengo);

            if (mzaziChanzo != mzaziLengo) {
                unganisha(mzazi, mzaziChanzo, mzaziLengo);
                gharamaNdogo += kingo.uzito;
                idadiKingo++;
            }
            if(idadiKingo == n -1) break; //uboreshaji: simamisha wakati nodi zote zimeunganishwa
        }

        return gharamaNdogo;
    }

    private static int find(int[] mzazi, int i) {
        if (mzazi[i] == i) {
            return i;
        }
        return mzazi[i] = find(mzazi, mzazi[i]); // Ukandamizaji wa njia
    }

    private static void unganisha(int[] mzazi, int x, int y) {
        int mziziX = find(mzazi, x);
        int mziziY = find(mzazi, y);
        mzazi[mziziX] = mziziY;
    }

    public static void main(String[] args) {
        int n = 3;
        int[][] pointi = {{0,0},{2,2},{3,10}};
        int gharamaNdogo = gharamaNdogoUnganishaMiji(n, pointi);
        System.out.println("Gharama ndogo kuunganisha miji yote: " + gharamaNdogo); // Matokeo: 17

        n = 5;
        pointi = new int[][]{{0,0},{2,2},{3,10},{5,2},{7,0}};
        gharamaNdogo = gharamaNdogoUnganishaMiji(n, pointi);
        System.out.println("Gharama ndogo kuunganisha miji yote: " + gharamaNdogo); // Matokeo: 20
    }
}
